# Lancer depuis C:\himatech dans PowerShell :
#   Set-ExecutionPolicy -Scope Process -ExecutionPolicy Bypass
#   .\installer.ps1
# ============================================================

$base = "C:\himatech"
Write-Host "=== Installation des corrections Himatech ===" -ForegroundColor Cyan

function Write-Clean {
    param([string]$path, [string]$content)
    $dir = Split-Path $path
    if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    [System.IO.File]::WriteAllText($path, $content, [System.Text.UTF8Encoding]::new($false))
    Write-Host "  OK : $path" -ForegroundColor Green
}

function Write-B64 {
    param([string]$path, [string]$b64)
    $dir = Split-Path $path
    if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    [System.IO.File]::WriteAllBytes($path, [System.Convert]::FromBase64String($b64))
    Write-Host "  OK : $path" -ForegroundColor Green
}

# ============================================================
# 1. vite.config.js
# ============================================================
Write-Host "`n[1/5] vite.config.js" -ForegroundColor Yellow
Write-Clean "$base\vite.config.js" @"
import { defineConfig } from 'vite';
import laravel from 'laravel-vite-plugin';
import { bunny } from 'laravel-vite-plugin/fonts';
import tailwindcss from '@tailwindcss/vite';

export default defineConfig({
    plugins: [
        laravel({
            input: ['resources/css/app.css', 'resources/js/app.js'],
            refresh: true,
            fonts: [
                bunny('Instrument Sans', { weights: [400, 500, 600] }),
            ],
        }),
        tailwindcss(),
    ],
    server: {
        watch: { ignored: ['**/storage/framework/views/**'] },
    },
});
"@

# ============================================================
# 2. resources/css/app.css
# ============================================================
Write-Host "`n[2/5] resources/css/app.css" -ForegroundColor Yellow
